sql:
SELECT payments.payment_id, users.user_name
FROM payments
JOIN users ON payments.user_id = users.user_id;

SELECT transaction_id
FROM payments
WHERE user_id = 1;

external_knowledge:
- 'shady transactions' refers to payments that are flagged as fraudulent;
- 'dodgy deals' refers to the basket value in cents of these fraudulent payments;
- 'suspicious payments' refers to the same fraudulent payments;
- 'total fees collected' refers to the sum of transaction fees in cents for these fraudulent payments.

sql:
SELECT mid
FROM merchant_ids
WHERE mid = '1';

SELECT AVG(score) AS average_fraud_score
FROM fraud_detection
WHERE is_fraudulent = 1;

SELECT SUM(fee_amount_cents) AS total_processing_fee_cents
FROM transaction_fees
WHERE fee_type = 'processing fee';

external_knowledge:
Merchant ID '1' refers to the first merchant;
Successful transactions indicate that the payment status is 'completed';
Genuine transactions mean the payment is not identified as fraudulent.

